      </thead>
      <tbody>
        {labels.map((gold) => {
          const row = confusion[gold] ?? {};
          return (
            <tr key={gold}>
              <th scope="row">
                <code>{gold}</code>
              </th>
              {labels.map((pred) => (
                <td key={pred}>{row[pred] ?? 0}</td>
              ))}
            </tr>
          );
        })}
      </tbody>
    </table>
  );
}

