}
.qh-actions {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-wrap: wrap;
  gap: 0.6rem;
}
.qh-action-link {
  display: inline-block;
  padding: 0.35rem 0.7rem;
  border: 1px solid var(--border, #2a2620);
  font-family: var(--font-mono, ui-monospace, monospace);
  font-size: 0.85rem;
  text-decoration: none;
  color: inherit;
}
.qh-action-link:hover {
  background: var(--surface, #11100d);
}
`;
